:root, [data-theme="dark"] {
  --bg-primary: #080E0C;
  --bg-secondary: #0D1612;
  --bg-card: #0D1612;
  --border: #243830;
  --accent-orange: #FF5A1F;
  --accent-teal: #00A896;
  --text-primary: #F0F0EE;
  --text-secondary: #7AA09A;
  --text-muted: #4E7870;
}

* {
  box-sizing: border-box;
  -webkit-tap-highlight-color: transparent;
}

html {
  scroll-behavior: smooth;
}

html, body {
  margin: 0;
  padding: 0;
  background-color: var(--bg-primary);
  color: var(--text-primary);
  font-family: 'IBM Plex Sans', sans-serif;
  min-height: 100dvh;
  overflow-x: hidden;
}

#root {
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
}

::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: var(--bg-primary); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

.btn-primary {
  background: var(--accent-orange);
  color: #080E0C;
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 600;
  font-size: 14px;
  border-radius: 8px;
  padding: 11px 20px;
  border: none;
  cursor: pointer;
  box-shadow: 0 0 14px rgba(255, 90, 31, 0.2);
  transition: filter 0.15s;
  min-height: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
}
.btn-primary:hover { filter: brightness(1.1); }
.btn-primary:active { filter: brightness(0.95); }
.btn-primary:disabled { opacity: 0.5; cursor: not-allowed; }

.btn-outline {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 600;
  font-size: 14px;
  border-radius: 8px;
  padding: 11px 20px;
  cursor: pointer;
  transition: border-color 0.15s, color 0.15s;
  min-height: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  text-decoration: none;
}
.btn-outline:hover { border-color: var(--text-secondary); color: var(--text-primary); }

.btn-ghost {
  background: transparent;
  border: none;
  color: var(--text-secondary);
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 500;
  font-size: 14px;
  cursor: pointer;
  padding: 8px 12px;
  border-radius: 8px;
  transition: color 0.15s;
  min-height: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  text-decoration: none;
}
.btn-ghost:hover { color: var(--text-primary); }

.input {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text-primary);
  font-family: 'IBM Plex Sans', sans-serif;
  font-size: 15px;
  padding: 10px 12px;
  width: 100%;
  outline: none;
  transition: border-color 0.15s;
  min-height: 44px;
}
.input:focus { border-color: var(--accent-teal); }
.input::placeholder { color: var(--text-muted); }

.label {
  font-family: 'IBM Plex Sans', sans-serif;
  font-size: 11px;
  letter-spacing: 1.5px;
  color: var(--text-muted);
  text-transform: uppercase;
  display: block;
  margin-bottom: 6px;
}

.section-label {
  font-family: 'IBM Plex Sans', sans-serif;
  font-size: 11px;
  letter-spacing: 1.5px;
  color: var(--accent-teal);
  text-transform: uppercase;
  margin: 0 0 12px;
}

h1, h2, h3 {
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 600;
  margin: 0;
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(18px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.anim-fade-up {
  animation: fadeUp 0.7s ease-out both;
}

.anim-fade-up-delay-1 {
  animation: fadeUp 0.7s ease-out 0.12s both;
}

.anim-fade-up-delay-2 {
  animation: fadeUp 0.7s ease-out 0.24s both;
}

.anim-fade-in {
  animation: fadeIn 1s ease-out both;
}

.phone-frame {
  position: relative;
  width: 100%;
  max-width: 260px;
  margin: 0 auto;
  background: #050807;
  border: 2px solid var(--border);
  border-radius: 28px;
  padding: 10px 8px 12px;
  box-shadow: 0 24px 48px rgba(0, 0, 0, 0.45);
}

.phone-frame::before {
  content: '';
  display: block;
  width: 72px;
  height: 6px;
  background: var(--border);
  border-radius: 999px;
  margin: 0 auto 10px;
}

.phone-screen {
  aspect-ratio: 9 / 19.5;
  border-radius: 18px;
  overflow: hidden;
  background: var(--bg-secondary);
  border: 1px solid rgba(36, 56, 48, 0.8);
}

.phone-screen img,
.phone-screen video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.phone-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 20px;
  text-align: center;
  background:
    linear-gradient(160deg, rgba(255, 90, 31, 0.08), transparent 50%),
    var(--bg-secondary);
}

.phone-placeholder span {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 13px;
  color: var(--text-secondary);
}

.phone-placeholder small {
  font-size: 11px;
  color: var(--text-muted);
  line-height: 1.4;
}

import { useState } from 'react'
import { supabase } from '../lib/supabase'

export default function WaitlistForm({ id = 'waitlist', compact = false }) {
  const [email, setEmail] = useState('')
  const [status, setStatus] = useState('idle') // idle | loading | success | error | duplicate
  const [message, setMessage] = useState('')

  async function handleSubmit(e) {
    e.preventDefault()
    const trimmed = email.trim().toLowerCase()
    if (!trimmed || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(trimmed)) {
      setStatus('error')
      setMessage('Enter a valid email.')
      return
    }

    setStatus('loading')
    setMessage('')

    try {
      // Prefer serverless API when configured; fall back to anon insert (RLS INSERT-only)
      const res = await fetch('/api/waitlist', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: trimmed, source: 'marketing' }),
      })

      if (res.status !== 404 && res.headers.get('content-type')?.includes('application/json')) {
        const data = await res.json().catch(() => ({}))
        if (res.status === 409 || data.code === 'duplicate') {
          setStatus('duplicate')
          setMessage("You're already on the list.")
          return
        }
        if (res.ok) {
          setStatus('success')
          setMessage("You're on the list. We'll be in touch.")
          setEmail('')
          return
        }
        // If API is misconfigured (500), try client insert below
        if (res.status !== 500) {
          setStatus('error')
          setMessage(data.error || 'Something went wrong. Try again.')
          return
        }
      }

      if (!supabase) {
        setStatus('error')
        setMessage('Waitlist is not configured yet.')
        return
      }

      const { error } = await supabase
        .from('marketing_waitlist')
        .insert({ email: trimmed, source: 'marketing' })

      if (error) {
        if (error.code === '23505' || /duplicate|unique/i.test(error.message)) {
          setStatus('duplicate')
          setMessage("You're already on the list.")
          return
        }
        setStatus('error')
        setMessage(error.message || 'Something went wrong. Try again.')
        return
      }

      setStatus('success')
      setMessage("You're on the list. We'll be in touch.")
      setEmail('')
    } catch {
      setStatus('error')
      setMessage('Network error. Try again.')
    }
  }

  return (
    <div className="w-full max-w-md">
      <form
        id={id}
        onSubmit={handleSubmit}
        className={compact ? 'flex flex-col gap-3' : 'flex flex-col sm:flex-row gap-3'}
        noValidate
      >
        <label className="sr-only" htmlFor={`${id}-email`}>
          Email
        </label>
        <input
          id={`${id}-email`}
          className="input flex-1"
          type="email"
          name="email"
          autoComplete="email"
          placeholder="you@email.com"
          value={email}
          onChange={(e) => {
            setEmail(e.target.value)
            if (status !== 'idle' && status !== 'loading') setStatus('idle')
          }}
          disabled={status === 'loading' || status === 'success'}
          required
        />
        <button
          type="submit"
          className="btn-primary whitespace-nowrap sm:min-w-[140px]"
          disabled={status === 'loading' || status === 'success'}
        >
          {status === 'loading' ? 'Joining…' : status === 'success' ? 'Joined' : 'Join waitlist'}
        </button>
      </form>
      {(status === 'success' || status === 'duplicate' || status === 'error') && (
        <p
          className={`mt-2 text-sm ${
            status === 'error' ? 'text-[var(--accent-orange)]' : 'text-[var(--accent-teal)]'
          }`}
          role="status"
        >
          {message}
        </p>
      )}
    </div>
  )
}

import { useState, useEffect } from 'react'

